INSERT INTO "Items" ("Id", "Name", "ImageUri", "Type", "Cost", "Rarity", "Description") VALUES (509, 'Wretched Wings', 'https://static.wikia.nocookie.net/overwatch_gamepedia/images/d/de/Item_Reaper_Wretched_Wings.png/revision/latest/scale-to-width-down/100?cb=20250923170828', 'Hero Item (Survival)', '10000.0', 'Epic', 'While using [Wraith Form] gain the ability to fly and gain 20% Move Speed.');
INSERT INTO "Items" ("Id", "Name", "ImageUri", "Type", "Cost", "Rarity", "Description") VALUES (510, 'Backstabber', 'https://static.wikia.nocookie.net/overwatch_gamepedia/images/9/92/Backstabber_Power.png/revision/latest/scale-to-width-down/100?cb=20250923170853', 'Stadium Power', '0.0', 'Common', 'After using an ability, your next shot deals 50% additional damage over 3s to enemies struck from behind.');
