INSERT INTO "Items" ("Id", "Name", "ImageUri", "Type", "Cost", "Rarity", "Description") VALUES (514, 'Shrouded Shrapnel', 'https://static.wikia.nocookie.net/overwatch_gamepedia/images/f/f1/Power_Reaper_Shrouded_Shrapnel.png/revision/latest/scale-to-width-down/100?cb=20250923170946', 'Stadium Power', '0.0', 'Common', 'Using [Wraith Form] increases the number of pellets per shot in your next magazine by 25% and its spread by 50%.');
