INSERT INTO "Items" ("Id", "Name", "ImageUri", "Type", "Cost", "Rarity", "Description") VALUES (520, 'Ghosted', 'https://static.wikia.nocookie.net/overwatch_gamepedia/images/6/6b/Power_Reaper_Ghosted.png/revision/latest/scale-to-width-down/100?cb=20250923171100', 'Stadium Power', '0.0', 'Common', 'While in [Wraith Form], passing through enemies slows their Move speed and Attack Speed by 30% for 3s.');
