INSERT INTO "Items" ("Id", "Name", "ImageUri", "Type", "Cost", "Rarity", "Description") VALUES (576, 'Lock and Load', 'https://static.wikia.nocookie.net/overwatch_gamepedia/images/b/bb/Power_Sojourn_Lock_and_Load.png/revision/latest/scale-to-width-down/100?cb=20251017150820', 'Stadium Power', '0.0', 'Common', 'During [Power Slide], [Railgun] restores 100% of your Max Ammo every 1s.');
