INSERT INTO "Items" ("Id", "Name", "ImageUri", "Type", "Cost", "Rarity", "Description") VALUES (578, 'Zoom Zoom Zoom', 'https://static.wikia.nocookie.net/overwatch_gamepedia/images/8/84/Power_Sojourn_Zoom_Zoom_Zoom.png/revision/latest/scale-to-width-down/100?cb=20251017150857', 'Stadium Power', '0.0', 'Common', 'Gain an additional [Power Slide] charge.');
INSERT INTO "Items" ("Id", "Name", "ImageUri", "Type", "Cost", "Rarity", "Description") VALUES (579, 'Commotion Cycle', 'https://static.wikia.nocookie.net/overwatch_gamepedia/images/9/9e/Power_Sojourn_Commotion_Cycle.png/revision/latest/scale-to-width-down/100?cb=20251017150929', 'Stadium Power', '0.0', 'Common', 'Dealing damage with [Charged Shot] refunds up to 35% of your ability cooldowns, based on the [Railgun] Charge spent.');
INSERT INTO "Items" ("Id", "Name", "ImageUri", "Type", "Cost", "Rarity", "Description") VALUES (580, 'Experimental Tech', 'https://static.wikia.nocookie.net/overwatch_gamepedia/images/d/d6/Power_Sojourn_Experimental_Tech.png/revision/latest/scale-to-width-down/100?cb=20251017151000', 'Stadium Power', '0.0', 'Common', '[Disruptor Shot] slows enemies within its area for 25%. Gain [Railgun] Charge equal to 50% of ability damage dealt.');
INSERT INTO "Items" ("Id", "Name", "ImageUri", "Type", "Cost", "Rarity", "Description") VALUES (581, 'Hard Stuck', 'https://static.wikia.nocookie.net/overwatch_gamepedia/images/f/f2/Power_Sojourn_Hard_Stuck.png/revision/latest/scale-to-width-down/100?cb=20251017151022', 'Stadium Power', '0.0', 'Common', '[Disruptor Shot] can stick to enemies. Stuck [Disruptor Shots] deal 25% less damage.');
INSERT INTO "Items" ("Id", "Name", "ImageUri", "Type", "Cost", "Rarity", "Description") VALUES (582, 'Conductor Chase', 'https://static.wikia.nocookie.net/overwatch_gamepedia/images/7/7a/Power_Sojourn_Conductor_Chase.png/revision/latest/scale-to-width-down/100?cb=20251017151039', 'Stadium Power', '0.0', 'Common', 'During [Power Slide] and the jump after, gain 10% [Railgun] Charge and restore 50% of your Max Ammo every 1s. [Railgun] Charge decays 75% slower.');
INSERT INTO "Items" ("Id", "Name", "ImageUri", "Type", "Cost", "Rarity", "Description") VALUES (583, 'Overcharge', 'https://static.wikia.nocookie.net/overwatch_gamepedia/images/1/1b/Power_Sojourn_Overcharge.png/revision/latest/scale-to-width-down/100?cb=20251017151058', 'Stadium Power', '0.0', 'Common', 'Maximum [Railgun] Charge increased to 150. Fully-charged attacks and abilities still only consume up to 100 Charge.');
