INSERT INTO "Items" ("Id", "Name", "ImageUri", "Type", "Cost", "Rarity", "Description") VALUES (590, 'Skjutsnabbt System', 'https://static.wikia.nocookie.net/overwatch_gamepedia/images/a/ad/Skjutsnabbt_System.png/revision/latest/scale-to-width-down/100?cb=20251017164957', 'Hero Item (Weapon)', '10000.0', 'Epic', 'When [Overload] expires, gain 20% Attack Speed for 3s.');
