INSERT INTO "Items" ("Id", "Name", "ImageUri", "Type", "Cost", "Rarity", "Description") VALUES (601, 'Swedish Sauna', 'https://static.wikia.nocookie.net/overwatch_gamepedia/images/7/70/Swedish_Sauna.png/revision/latest/scale-to-width-down/100?cb=20251017165454', 'Stadium Power', '0.0', 'Common', '[Molten Core] heals allied heroes within it for 50% of [Molten Core] Damage every 1s.');
