INSERT INTO "Items" ("Id", "Name", "ImageUri", "Type", "Cost", "Rarity", "Description") VALUES (608, 'Riveting', 'https://static.wikia.nocookie.net/overwatch_gamepedia/images/5/54/Riveting.png/revision/latest/scale-to-width-down/100?cb=20251017165744', 'Stadium Power', '0.0', 'Common', 'Every 5th [Rivet Gun] shot shoots both your Primary and Secondary Fire. The bonus shot deals 10% reduced damage.');
