INSERT INTO "Items" ("Id", "Name", "ImageUri", "Type", "Cost", "Rarity", "Description") VALUES (617, 'Slipstream Salve', 'https://static.wikia.nocookie.net/overwatch_gamepedia/images/0/02/Item_Tracer_Slipstream_Salve.png/revision/latest/scale-to-width-down/100?cb=20250923172109', 'Hero Item (Survival)', '10000.0', 'Epic', '[Recall] always restores at least 70% of your life.');
INSERT INTO "Items" ("Id", "Name", "ImageUri", "Type", "Cost", "Rarity", "Description") VALUES (618, 'Custom Kicks', 'https://static.wikia.nocookie.net/overwatch_gamepedia/images/0/0e/Item_Tracer_Custom_Kicks.png/revision/latest/scale-to-width-down/100?cb=20250923172123', 'Hero Item (Survival)', '10000.0', 'Epic', 'When you use [Blink], grant yourself and allies within 6m 10% Move Speed for 1s.');
INSERT INTO "Items" ("Id", "Name", "ImageUri", "Type", "Cost", "Rarity", "Description") VALUES (619, 'Flash Fist', 'https://static.wikia.nocookie.net/overwatch_gamepedia/images/6/66/Power_Tracer_Flash_Fist.png/revision/latest/scale-to-width-down/100?cb=20250923172144', 'Stadium Power', '0.0', 'Common', 'For 1s after using [Blink], your next [Quick Melee] is affected by Ability Power, deals 25 extra damage, and knocks enemies back.');
INSERT INTO "Items" ("Id", "Name", "ImageUri", "Type", "Cost", "Rarity", "Description") VALUES (620, 'Get Stuffed!', 'https://static.wikia.nocookie.net/overwatch_gamepedia/images/3/35/Power_Tracer_Get_Stuffed%21.png/revision/latest/scale-to-width-down/100?cb=20250923172156', 'Stadium Power', '0.0', 'Common', '[Quick Melee] hits grant 5% Ultimate Charge and reduce [Recall] cooldown by 2s.');
INSERT INTO "Items" ("Id", "Name", "ImageUri", "Type", "Cost", "Rarity", "Description") VALUES (621, 'Blink Of An Eye', 'https://static.wikia.nocookie.net/overwatch_gamepedia/images/a/a0/Power_Tracer_Blink_of_an_Eye.png/revision/latest/scale-to-width-down/100?cb=20250923172207', 'Stadium Power', '0.0', 'Common', 'Critical hits reduce the cooldown of [Blink] by 0.04s.');
INSERT INTO "Items" ("Id", "Name", "ImageUri", "Type", "Cost", "Rarity", "Description") VALUES (622, 'Quantum Clip', 'https://static.wikia.nocookie.net/overwatch_gamepedia/images/8/87/Power_Tracer_Quantum_Clip.png/revision/latest/scale-to-width-down/100?cb=20250923172223', 'Stadium Power', '0.0', 'Common', 'If you use [Blink] while reloading, gain 25% Max Ammo and 10% Weapon Lifesteal until you reload.');
INSERT INTO "Items" ("Id", "Name", "ImageUri", "Type", "Cost", "Rarity", "Description") VALUES (623, 'Alternate Ending', 'https://static.wikia.nocookie.net/overwatch_gamepedia/images/d/d1/Power_Tracer_Alternate_Ending.png/revision/latest/scale-to-width-down/100?cb=20250923172234', 'Stadium Power', '0.0', 'Common', 'When you use [Recall], heal allies within 6m for 100% of the damage they have taken in the last 3s.');
INSERT INTO "Items" ("Id", "Name", "ImageUri", "Type", "Cost", "Rarity", "Description") VALUES (624, 'Auto Recall', 'https://static.wikia.nocookie.net/overwatch_gamepedia/images/a/af/Power_Tracer_Auto_Recall.png/revision/latest/scale-to-width-down/100?cb=20250923172245', 'Stadium Power', '0.0', 'Common', 'Once per round, if you would die, instead use [Recall] for free. Spending your Ultimate Charge reduces [Recall]''s cooldown by 50%.');
