INSERT INTO "Items" ("Id", "Name", "ImageUri", "Type", "Cost", "Rarity", "Description") VALUES (627, 'Temportal', 'https://static.wikia.nocookie.net/overwatch_gamepedia/images/7/78/Power_Tracer_Temportal.png/revision/latest/scale-to-width-down/100?cb=20250923172326', 'Stadium Power', '0.0', 'Common', '[Recall] leaves behind a Temporal Portal for 8s. Up to 3 allies can [Interact] with it once to [Recall] back in time 1s.');
