INSERT INTO "Items" ("Id", "Name", "ImageUri", "Type", "Cost", "Rarity", "Description") VALUES (629, 'Timelapse', 'https://static.wikia.nocookie.net/overwatch_gamepedia/images/0/01/Power_Tracer_Timelapse.png/revision/latest/scale-to-width-down/100?cb=20250923172353', 'Stadium Power', '0.0', 'Common', 'Hitting 2 consecutive shots on the same target without missing deals  2 extra damage over 2s.');
INSERT INTO "Items" ("Id", "Name", "ImageUri", "Type", "Cost", "Rarity", "Description") VALUES (630, 'Impulsive', 'https://static.wikia.nocookie.net/overwatch_gamepedia/images/9/96/Power_Tracer_Impulsive.png/revision/latest/scale-to-width-down/100?cb=20250923172407', 'Stadium Power', '0.0', 'Common', 'When you use [Recall], throw a [Pulse Bomb] that detonates 50% faster but deals 60% less damage.');
