INSERT INTO "Items" ("Id", "Name", "ImageUri", "Type", "Cost", "Rarity", "Description") VALUES (777, 'Vicious Vow', 'https://static.wikia.nocookie.net/overwatch_gamepedia/images/6/66/Item_Vendetta_Vicious_Vow.png/revision/latest/scale-to-width-down/100?cb=20260217100233', 'Hero Item (Survival)', '9000.0', 'Epic', 'While channeling [Sundering Blade], gain  25 Overhealth every 1s, up to  50.');
INSERT INTO "Items" ("Id", "Name", "ImageUri", "Type", "Cost", "Rarity", "Description") VALUES (778, 'Continuum', 'https://static.wikia.nocookie.net/overwatch_gamepedia/images/1/18/Power_Continuum.png/revision/latest/scale-to-width-down/100?cb=20260217100324', 'Stadium Power', '0.0', 'Common', 'Before dying, temporarily come back to life with 15% Max Life for each [Onlaught] stack and become hindered. (90s Cooldown)');
INSERT INTO "Items" ("Id", "Name", "ImageUri", "Type", "Cost", "Rarity", "Description") VALUES (779, 'Rising Rampage', 'https://static.wikia.nocookie.net/overwatch_gamepedia/images/c/ca/Power_Rising_Rampage.png/revision/latest/scale-to-width-down/100?cb=20260217100348', 'Stadium Power', '0.0', 'Common', '[Onslaught]''s maximum stacks increases by 1 after earning 2 Eliminations, up to 3.');
INSERT INTO "Items" ("Id", "Name", "ImageUri", "Type", "Cost", "Rarity", "Description") VALUES (780, 'Overloaded Strike', 'https://static.wikia.nocookie.net/overwatch_gamepedia/images/c/cf/Power_Vendetta_Overloaded_Strike.png/revision/latest/scale-to-width-down/100?cb=20260217100404', 'Stadium Power', '0.0', 'Common', 'After using [Soaring Slice], your next Airborne [Overhead Strike] can channel a level 1 [Sundering Blade] with 25% increased damage.');
INSERT INTO "Items" ("Id", "Name", "ImageUri", "Type", "Cost", "Rarity", "Description") VALUES (781, 'Skycut', 'https://static.wikia.nocookie.net/overwatch_gamepedia/images/1/19/Power_Vendetta_Skycut.png/revision/latest/scale-to-width-down/100?cb=20260217100422', 'Stadium Power', '0.0', 'Common', 'After using [Soaring Slice], the next [Overhead Strike] shoots a [Projected Edge] with 75% damage when landing.');
INSERT INTO "Items" ("Id", "Name", "ImageUri", "Type", "Cost", "Rarity", "Description") VALUES (782, 'Defiance Core', 'https://static.wikia.nocookie.net/overwatch_gamepedia/images/6/65/Power_Vendetta_Defiance_Core.png/revision/latest/scale-to-width-down/100?cb=20260217100444', 'Stadium Power', '0.0', 'Common', '[Warding Stance] energy regenerates now even while blocking at 75% rate. For every [Projected Edge] fired, reduce [Whirlwind Dash] and [Soaring Slice] cooldown by 0.5s.');
