INSERT INTO "Items" ("Id", "Name", "ImageUri", "Type", "Cost", "Rarity", "Description") VALUES (784, 'Riposte', 'https://static.wikia.nocookie.net/overwatch_gamepedia/images/a/a6/Power_Vendetta_Riposte.png/revision/latest/scale-to-width-down/100?cb=20260217100521', 'Stadium Power', '0.0', 'Common', 'After blocking ranged damage, remove [Warding Stance]''s Move Speed penalty. Your next swing becomes an [Overhead Strike].');
