INSERT INTO "Items" ("Id", "Name", "ImageUri", "Type", "Cost", "Rarity", "Description") VALUES (787, 'Exalted Empress', 'https://static.wikia.nocookie.net/overwatch_gamepedia/images/0/05/Power_Vendetta_Exalted_Empress.png/revision/latest/scale-to-width-down/100?cb=20260217100620', 'Stadium Power', '0.0', 'Common', 'After using [Soaring Slice], [Overhead Strike] and [Sundering Blade] give 30% of damage as temporary Overhealth, up to 200.');
INSERT INTO "Items" ("Id", "Name", "ImageUri", "Type", "Cost", "Rarity", "Description") VALUES (788, 'Up And Over', 'https://static.wikia.nocookie.net/overwatch_gamepedia/images/3/36/Item_Vendetta_Marzia%27s_Mastery.png/revision/latest/scale-to-width-down/100?cb=20260217100030', 'Hero Item (Survival)', '9500.0', 'Epic', 'Using [Soaring Slice] gives 30% of missing life as Overhealth for 5s.');
