INSERT INTO "Items" ("Id", "Name", "ImageUri", "Type", "Cost", "Rarity", "Description") VALUES (829, 'Double Dose', 'https://static.wikia.nocookie.net/overwatch_gamepedia/images/e/e8/Power_Mercy_Protective_Beam.png/revision/latest/scale-to-width-down/100?cb=20250925072306', 'Stadium Power', '0.0', 'Common', 'Gain an extra charge of [Flash Heal]. When [Valkyrie] is activated, refresh a charge of [Flash Heal].');
INSERT INTO "Items" ("Id", "Name", "ImageUri", "Type", "Cost", "Rarity", "Description") VALUES (830, 'Triage Unit (Power)', 'https://static.wikia.nocookie.net/overwatch_gamepedia/images/6/65/Power_Mercy_Triage_Unit.png/revision/latest/scale-to-width-down/100?cb=20250925072904', 'Stadium Power', '0.0', 'Common', 'When using [Guardian Angel] on allies below 50% Life, they receive 25% more healing from you for 3s.');
INSERT INTO "Items" ("Id", "Name", "ImageUri", "Type", "Cost", "Rarity", "Description") VALUES (831, 'Angelic Acrobatics (Item)', 'https://static.wikia.nocookie.net/overwatch_gamepedia/images/c/ca/Item_Mercy_Angelic_Acrobatics.png/revision/latest/scale-to-width-down/100?cb=20250925072009', 'Hero Item (Ability)', '11000.0', 'Epic', '[Guardian Angel]''s cooldown starts as soon as you jump or crouch.');
INSERT INTO "Items" ("Id", "Name", "ImageUri", "Type", "Cost", "Rarity", "Description") VALUES (832, 'OR-15 Escalator', 'https://static.wikia.nocookie.net/overwatch_gamepedia/images/0/01/Item_Orisa_Optimized_Energy.png/revision/latest/scale-to-width-down/100?cb=20250921180921', 'Hero Item (Weapon)', '10000.0', 'Epic', 'Gain Weapon Power based on your [Heat], up to 40% Weapon Power.');
INSERT INTO "Items" ("Id", "Name", "ImageUri", "Type", "Cost", "Rarity", "Description") VALUES (833, 'Core Cooling', 'https://static.wikia.nocookie.net/overwatch_gamepedia/images/a/a6/Power_Orisa_Ride_With_Me.png/revision/latest/scale-to-width-down/100?cb=20250921181721', 'Stadium Power', '0.0', 'Common', 'While [Fortify] is active, reduce [Heat] generated by 90% and gain 10% Attack Speed.');
INSERT INTO "Items" ("Id", "Name", "ImageUri", "Type", "Cost", "Rarity", "Description") VALUES (834, 'Critical Charger', 'https://static.wikia.nocookie.net/overwatch_gamepedia/images/f/f7/Power_Orisa_Factory_Reset.png/revision/latest/scale-to-width-down/100?cb=20250921181627', 'Stadium Power', '0.0', 'Common', '[Energy Javelin] can crit for 75% bonus damage.
INSERT INTO "Items" ("Id", "Name", "ImageUri", "Type", "Cost", "Rarity", "Description") VALUES (835, 'Oladele-Copter Blades (Item)', 'https://static.wikia.nocookie.net/overwatch_gamepedia/images/1/16/Item_Orisa_Oladele-copter_Blades.png/revision/latest/scale-to-width-down/100?cb=20250921181205', 'Hero Item (Ability)', '10000.0', 'Epic', 'While Using Javelin Spin, gain free flight and 20% Move Speed.');
INSERT INTO "Items" ("Id", "Name", "ImageUri", "Type", "Cost", "Rarity", "Description") VALUES (836, 'Rocket Propellant', 'https://static.wikia.nocookie.net/overwatch_gamepedia/images/3/3f/Item_Pharah_Ana%27s_Aim-Assist.png/revision/latest/scale-to-width-down/100?cb=20250923133631', 'Hero Item (Survival)', '11000.0', 'Epic', 'After using an ability or Gadget, gain 75% [Rocket Launcher] Self Knockback for 3s.');
INSERT INTO "Items" ("Id", "Name", "ImageUri", "Type", "Cost", "Rarity", "Description") VALUES (837, 'Nosedive', 'https://static.wikia.nocookie.net/overwatch_gamepedia/images/b/bc/Power_Pharah_Fuel_Conversion.png/revision/latest/scale-to-width-down/100?cb=20250923133907', 'Stadium Power', '0.0', 'Common', 'Ability: While Airborne, use [Crouch] to dash towards the ground and restore 50% fuel.
(6s Cooldown).');
INSERT INTO "Items" ("Id", "Name", "ImageUri", "Type", "Cost", "Rarity", "Description") VALUES (838, 'Bloodletters', 'https://static.wikia.nocookie.net/overwatch_gamepedia/images/2/2e/Power_Reaper_Backstabber.png/revision/latest/scale-to-width-down/100?cb=20250923170853', 'Stadium Power', '0.0', 'Common', '[Dire Triggers] deal  30 additional damage over 3s to Airborne enemies and enemies beyond 8m.');
INSERT INTO "Items" ("Id", "Name", "ImageUri", "Type", "Cost", "Rarity", "Description") VALUES (839, 'Trigger Finger', 'https://static.wikia.nocookie.net/overwatch_gamepedia/images/d/d9/Power_Reaper_Vampiric_Touch.png/revision/latest/scale-to-width-down/100?cb=20250923171012', 'Stadium Power', '0.0', 'Common', 'After using an ability or Gadget or reloading, refresh [Dire Triggers] cooldown.');
INSERT INTO "Items" ("Id", "Name", "ImageUri", "Type", "Cost", "Rarity", "Description") VALUES (840, 'Hellshroud', 'https://static.wikia.nocookie.net/overwatch_gamepedia/images/6/6b/Power_Reaper_Ghosted.png/revision/latest/scale-to-width-down/100?cb=20250923171100', 'Stadium Power', '0.0', 'Common', 'While in [Wraith Form], passing through enemies Burns them for 20% of your Max Life and slows their Move Speed and Attack Speed by 20% for 2s.');
INSERT INTO "Items" ("Id", "Name", "ImageUri", "Type", "Cost", "Rarity", "Description") VALUES (841, 'Wall of Life and Death', 'https://static.wikia.nocookie.net/overwatch_gamepedia/images/b/b4/Power_Reaper_Shared_Siphon.png/revision/latest/scale-to-width-down/100?cb=20250923170934', 'Stadium Power', '0.0', 'Common', 'While in [Wraith Form], become 50% larger and block incoming projectiles while healing all other allies within 6m for  35 every 1s.');
INSERT INTO "Items" ("Id", "Name", "ImageUri", "Type", "Cost", "Rarity", "Description") VALUES (842, 'Crusader Slam', 'https://static.wikia.nocookie.net/overwatch_gamepedia/images/4/4f/Power_Reinhardt_Amplification_Barrier.png/revision/latest/scale-to-width-down/100?cb=20250922162219', 'Stadium Power', '0.0', 'Common', 'Ability: While [Barrier Field] is active, use [Primary Fire] to deal [Melee] Damage equal to 5% of [Barrier Field] Health.
(8s Cooldown).');
INSERT INTO "Items" ("Id", "Name", "ImageUri", "Type", "Cost", "Rarity", "Description") VALUES (843, 'Iron Drift', 'https://static.wikia.nocookie.net/overwatch_gamepedia/images/a/a1/Power_Reinhardt_Vanguard.png/revision/latest/scale-to-width-down/100?cb=20250922162415', 'Stadium Power', '0.0', 'Common', '+200% [Charge] Duration.
INSERT INTO "Items" ("Id", "Name", "ImageUri", "Type", "Cost", "Rarity", "Description") VALUES (844, 'Overclocked Surge', 'https://static.wikia.nocookie.net/overwatch_gamepedia/images/0/02/Item_Sojourn_Murphy%27s_Motor_Module.png/revision/latest/scale-to-width-down/100?cb=20251017150420', 'Hero Item (Ability)', '10000.0', 'Epic', 'While [Overclock] is active, abilities refresh 300% faster. Elimination during [Overclock] increase its duration by 2s.');
INSERT INTO "Items" ("Id", "Name", "ImageUri", "Type", "Cost", "Rarity", "Description") VALUES (845, 'Charge Converter', 'https://static.wikia.nocookie.net/overwatch_gamepedia/images/7/7a/Item_Sojourn_Energy_Leech.png/revision/latest/scale-to-width-down/100?cb=20251017150620', 'Hero Item (Ability)', '11000.0', 'Epic', '[Charged Shot] grants 0.25% Ability Power for every 1 [Railgun] Charge spent for 3s, up to 40%.');
INSERT INTO "Items" ("Id", "Name", "ImageUri", "Type", "Cost", "Rarity", "Description") VALUES (846, 'Drill Kick', 'https://static.wikia.nocookie.net/overwatch_gamepedia/images/b/bb/Power_Sojourn_Lock_and_Load.png/revision/latest/scale-to-width-down/100?cb=20251017150820', 'Stadium Power', '0.0', 'Common', '+50% [Power Slide] Speed.
INSERT INTO "Items" ("Id", "Name", "ImageUri", "Type", "Cost", "Rarity", "Description") VALUES (847, 'Dynamic Dispatch', 'https://static.wikia.nocookie.net/overwatch_gamepedia/images/b/b1/Power_Sojourn_Reverberation_Rounds.png/revision/latest/scale-to-width-down/100?cb=20251017151121', 'Stadium Power', '0.0', 'Common', 'During [Power Slide] and the jump after, gain 50% [Charged Shot] projectile size, 35% Attack Speed, and 35% Weapon Lifesteal.');
INSERT INTO "Items" ("Id", "Name", "ImageUri", "Type", "Cost", "Rarity", "Description") VALUES (848, 'Aftershock', 'https://static.wikia.nocookie.net/overwatch_gamepedia/images/5/53/Power_Sojourn_Aftershock.png/revision/latest/scale-to-width-down/100?cb=20251017151207', 'Stadium Power', '0.0', 'Common', 'Fully-charged [Charged Shot] or [Charged Shot] critical hits trigger an explosion, dealing 50% damage to other nearby enemies.');
INSERT INTO "Items" ("Id", "Name", "ImageUri", "Type", "Cost", "Rarity", "Description") VALUES (849, 'Anchor Bolts', 'https://static.wikia.nocookie.net/overwatch_gamepedia/images/6/6a/Lindholm_Launcher.png/revision/latest/scale-to-width-down/100?cb=20251017165149', 'Hero Item (Ability)', '11000.0', 'Epic', '[Turrets] can now attach to walls and ceilings.');
INSERT INTO "Items" ("Id", "Name", "ImageUri", "Type", "Cost", "Rarity", "Description") VALUES (850, 'Hammer Throw', 'https://static.wikia.nocookie.net/overwatch_gamepedia/images/e/e3/Positive_Reinforcement.png/revision/latest/scale-to-width-down/100?cb=20251017165357', 'Stadium Power', '0.0', 'Common', 'Ability: While [Forge Hammer] is equipped, use [Secondary Fire] to throw it. It has 200% effectiveness on [Turrets] and allies.
(2s Cooldown).');
INSERT INTO "Items" ("Id", "Name", "ImageUri", "Type", "Cost", "Rarity", "Description") VALUES (851, 'Apex Bloodlust', 'https://static.wikia.nocookie.net/overwatch_gamepedia/images/0/03/Power_Vendetta_Up_and_Over.png/revision/latest/scale-to-width-down/100?cb=20260217100657', 'Stadium Power', '0.0', 'Common', 'Gain 5% Lifesteal and your abilities refresh 3% faster for each [Onslaught] stack you have.');
INSERT INTO "Items" ("Id", "Name", "ImageUri", "Type", "Cost", "Rarity", "Description") VALUES (852, 'Rampant Onslaught', 'https://static.wikia.nocookie.net/overwatch_gamepedia/images/8/80/Power_Vendetta_Rising_Rampage.png/revision/latest/scale-to-width-down/100?cb=20260217100348', 'Stadium Power', '0.0', 'Common', '[Onslaught]''s maximum stacks increases by 1 after every 2 Eliminations, up to 3.');
INSERT INTO "Items" ("Id", "Name", "ImageUri", "Type", "Cost", "Rarity", "Description") VALUES (853, 'Undying Fury', 'https://static.wikia.nocookie.net/overwatch_gamepedia/images/a/a6/Power_Vendetta_Continuum.png/revision/latest/scale-to-width-down/100?cb=20260217100324', 'Stadium Power', '0.0', 'Common', 'If you would die, instead become Hindered and prevent ally healing, gain decaying Overhealth equal to your Max Life, and double your [Onslaught] stacks and Lifesteal. (90s Cooldown)');
INSERT INTO "Items" ("Id", "Name", "ImageUri", "Type", "Cost", "Rarity", "Description") VALUES (854, 'Up And Over (Power)', 'https://static.wikia.nocookie.net/overwatch_gamepedia/images/0/03/Power_Vendetta_Up_and_Over.png/revision/latest/scale-to-width-down/100?cb=20260217100657', 'Stadium Power', '0.0', 'Common', 'Using [Soaring Slice] gives 35% of missing life as Overhealth for 10s.');
INSERT INTO "Items" ("Id", "Name", "ImageUri", "Type", "Cost", "Rarity", "Description") VALUES (855, 'Lucheng Launchers (Item)', 'https://static.wikia.nocookie.net/overwatch_gamepedia/images/c/cf/Item_Winston_Lucheng_Launchers.png/revision/latest/scale-to-width-down/100?cb=20250922163647', 'Hero Item (Ability)', '12000.0', 'Epic', 'During [Primal Rage], [Jump Pack]’s base damage becomes Electric and can increase up to an additional 100% while airborne.');
INSERT INTO "Items" ("Id", "Name", "ImageUri", "Type", "Cost", "Rarity", "Description") VALUES (856, 'Tidekeeper''s Connector', 'https://static.wikia.nocookie.net/overwatch_gamepedia/images/7/74/Item_Wuyang_Reservoir_Refresher.png/revision/latest/scale-to-width-down/100?cb=20251211184337', 'Hero Item (Weapon)', '10000.0', 'Epic', 'Every 1s while using Active [Restorative Stream] reduces [Guardian Wave]''s cooldown by 0.3s for every attached ally.');
INSERT INTO "Items" ("Id", "Name", "ImageUri", "Type", "Cost", "Rarity", "Description") VALUES (857, 'Aerial Surf', 'https://static.wikia.nocookie.net/overwatch_gamepedia/images/a/a9/Item_Wuyang_Metal_College_Module.png/revision/latest/scale-to-width-down/100?cb=20251211184115', 'Hero Item (Survival)', '10500.0', 'Epic', 'After using an ability or Gadget, your next jump gains 75% jump height. This bonus is doubled while [Rushing Torrent] is not active.');
INSERT INTO "Items" ("Id", "Name", "ImageUri", "Type", "Cost", "Rarity", "Description") VALUES (858, 'Ripple Sense', 'https://static.wikia.nocookie.net/overwatch_gamepedia/images/c/c7/Power_Wuyang_Wave_Lance.png/revision/latest/scale-to-width-down/100?cb=20251210193336', 'Stadium Power', '0.0', 'Common', 'Empowered [Water Orb] can be steered more freely and has 35% increased explosion radius. Every 5s, your next [Water Orb] will reveal all enemies within 8m on impact for 5s.');
INSERT INTO "Items" ("Id", "Name", "ImageUri", "Type", "Cost", "Rarity", "Description") VALUES (859, 'Bifurcation', 'https://static.wikia.nocookie.net/overwatch_gamepedia/images/1/11/Power_Wuyang_Tidekeeper_.png/revision/latest/scale-to-width-down/100?cb=20251210193604', 'Stadium Power', '0.0', 'Common', 'After using an ability, your Active [Restorative Stream] chains to the previous target with 100% healing for 4s. You can place an additional passive [Restorative Stream].');
INSERT INTO "Items" ("Id", "Name", "ImageUri", "Type", "Cost", "Rarity", "Description") VALUES (860, 'Current Confluence', 'https://static.wikia.nocookie.net/overwatch_gamepedia/images/3/31/Power_Wuyang_Shore_Up.png/revision/latest/scale-to-width-down/100?cb=20251210193355', 'Stadium Power', '0.0', 'Common', '+25% [Restorative Stream] Duration.
INSERT INTO "Items" ("Id", "Name", "ImageUri", "Type", "Cost", "Rarity", "Description") VALUES (861, 'Splash Strike', 'https://static.wikia.nocookie.net/overwatch_gamepedia/images/a/a0/Power_Wuyang_Splish_Slash.png/revision/latest/scale-to-width-down/100?cb=20251210193620', 'Stadium Power', '0.0', 'Common', 'While [Rushing Torrent] is active, using [Quick Melee] while Airborne creates a short [Guardian Wave] with 75% effectiveness around you.
(8s Cooldown.)');
INSERT INTO "Items" ("Id", "Name", "ImageUri", "Type", "Cost", "Rarity", "Description") VALUES (862, 'Waveshatter', 'https://static.wikia.nocookie.net/overwatch_gamepedia/images/c/c4/Power_Wuyang_Storm_Surge.png/revision/latest/scale-to-width-down/100?cb=20251210193744', 'Stadium Power', '0.0', 'Common', '[Guardian Wave] can crit enemies at close ranges and gains up to 150% more width and 75% more effectiveness based on time spent travelling downwards.');
INSERT INTO "Items" ("Id", "Name", "ImageUri", "Type", "Cost", "Rarity", "Description") VALUES (863, 'Wave Lance (Power)', 'https://static.wikia.nocookie.net/overwatch_gamepedia/images/c/c7/Power_Wuyang_Wave_Lance.png/revision/latest/scale-to-width-down/100?cb=20251210193336', 'Stadium Power', '0.0', 'Common', 'Non-empowered Primary Fire shoots straight and gains 150% increased projectile speed.');
INSERT INTO "Items" ("Id", "Name", "ImageUri", "Type", "Cost", "Rarity", "Description") VALUES (864, 'Charged Link', 'https://static.wikia.nocookie.net/overwatch_gamepedia/images/e/e7/Power_Zarya_Piercing_Beam.png/revision/latest/scale-to-width-down/100?cb=20250922164826', 'Stadium Power', '0.0', 'Common', '[Particle Cannon]''s Secondary Fire hits grant 2 [Energy] and increase [Particle Cannon]''s Primary Fire range by 20% for 3s.');
INSERT INTO "Items" ("Id", "Name", "ImageUri", "Type", "Cost", "Rarity", "Description") VALUES (865, 'Piercing Beam (Power)', 'https://static.wikia.nocookie.net/overwatch_gamepedia/images/e/e7/Power_Zarya_Piercing_Beam.png/revision/latest/scale-to-width-down/100?cb=20250922164826', 'Stadium Power', '0.0', 'Common', 'Above 80 [Energy], [Particle Cannon]''s Primary Fire will pierce enemies.');
INSERT INTO "Items" ("Id", "Name", "ImageUri", "Type", "Cost", "Rarity", "Description") VALUES (866, 'Sharpened Focus', 'https://static.wikia.nocookie.net/overwatch_gamepedia/images/5/58/Power_Zenyatta_Seeking_Salvation.png/revision/latest/scale-to-width-down/100?cb=20250925143500', 'Stadium Power', '0.0', 'Common', '[Orb of Destruction]''s Secondary Fire charges 20% faster. While charging, gain 5% Move Speed and Overhealth equal to 5% of your Max Life for every Orb charged.');
INSERT INTO "Items" ("Id", "Name", "ImageUri", "Type", "Cost", "Rarity", "Description") VALUES (867, 'Seeking Salvation (Power)', 'https://static.wikia.nocookie.net/overwatch_gamepedia/images/5/58/Power_Zenyatta_Seeking_Salvation.png/revision/latest/scale-to-width-down/100?cb=20250925143500', 'Stadium Power', '0.0', 'Common', '[Orb of Destruction]''s secondary fire projectiles home when aimed at a target below 50% Life.');
INSERT INTO "Items" ("Id", "Name", "ImageUri", "Type", "Cost", "Rarity", "Description") VALUES (868, 'Gadget Maximizer', 'https://static.wikia.nocookie.net/overwatch_gamepedia/images/2/2e/Item_General_Biotech_Maximizer.png/revision/latest/scale-to-width-down/100?cb=20260416133927', 'General Item (Ability)', '9500.0', 'Epic', '');
INSERT INTO "Items" ("Id", "Name", "ImageUri", "Type", "Cost", "Rarity", "Description") VALUES (869, 'Exo Springs', 'https://static.wikia.nocookie.net/overwatch_gamepedia/images/0/0f/Item_General_Exo_Springs.png/revision/latest/scale-to-width-down/100?cb=20260620092845', 'General Item (Survival)', '1500.0', 'Common', 'Holding [Crouch] for up to 0.75 seconds increases the height of your next jump by up to 250%.
(15s cooldown)');
