INSERT INTO "Items" ("Id", "Name", "ImageUri", "Type", "Cost", "Rarity", "Description") VALUES (872, 'Dragon Strike', 'https://static.wikia.nocookie.net/overwatch_gamepedia/images/9/9b/Item_Genji_Dragon_Strike.png/revision/latest/scale-to-width-down/100?cb=20260620093638', 'Hero Item (Ability)', '9500.0', 'Epic', '[Dragonblade]''s first swing is a wide [Swift Strike] that deals 100% bonus critical damage after a brief delay.');
INSERT INTO "Items" ("Id", "Name", "ImageUri", "Type", "Cost", "Rarity", "Description") VALUES (873, 'Deflect-o-Bot', 'https://static.wikia.nocookie.net/overwatch_gamepedia/images/5/51/Power_Genji_Deflect-o-Bot.png/revision/latest/scale-to-width-down/100?cb=20250923131627', 'Stadium Power', '0.0', 'Common', '+200% Deflected Projectile Speed.
INSERT INTO "Items" ("Id", "Name", "ImageUri", "Type", "Cost", "Rarity", "Description") VALUES (874, 'Blink Hop', 'https://static.wikia.nocookie.net/overwatch_gamepedia/images/a/a0/Power_Tracer_Blink_of_an_Eye.png/revision/latest/scale-to-width-down/100?cb=20250923172207', 'Stadium Power', '0.0', 'Common', '[Blink] teleports you 3m farther. If you use [Blink] while airborne, gain an air jump and reduce Blink cooldown by 0.2s.');
INSERT INTO "Items" ("Id", "Name", "ImageUri", "Type", "Cost", "Rarity", "Description") VALUES (875, 'Chrono Stabilizer', 'https://static.wikia.nocookie.net/overwatch_gamepedia/images/f/f2/Power_Tracer_T.RACER.png/revision/latest/scale-to-width-down/100?cb=20250923172306', 'Stadium Power', '0.0', 'Common', 'After you use [Blink], heal allies within 6m for  40 and yourself for  10.');
INSERT INTO "Items" ("Id", "Name", "ImageUri", "Type", "Cost", "Rarity", "Description") VALUES (876, 'Quantum Reload', 'https://static.wikia.nocookie.net/overwatch_gamepedia/images/7/73/Power_Tracer_Foresight.png/revision/latest/scale-to-width-down/100?cb=20250923172342', 'Stadium Power', '0.0', 'Common', 'After [Recalling], gain Ammo equal to 100% Max Ammo that decays over time.');
